{
  "recommendations": [
    {
      "title": "Fix mobile Safari session persistence after 2FA authentication",
      "reason": "Mobile login loops account for 30% of all tickets (6/20) and 100% were escalated with zero resolutions. Users consistently report completing 2FA on iOS Safari but immediately losing the session and redirecting back to sign-in. One user notes this started after a recent update, pointing to a regression in cookie handling—likely Safari ITP blocking the session cookie or a SameSite/Secure attribute misconfiguration on the auth token. Fixing this single issue would eliminate the largest ticket category and meaningfully reduce the 65% escalation rate."
    },
    {
      "title": "Overhaul the CSV export pipeline to address missing data, truncation, and encoding",
      "reason": "CSV export failures represent 20% of tickets (4/20) with zero resolutions, and the reports reveal at least four distinct bugs: headers-only output with no rows, empty columns that display correctly in-app, garbled accented characters from encoding mismatches, and a hard truncation at 200 rows. These are not edge cases—they block finance workflows entirely. The export pipeline needs a coordinated engineering fix covering data serialization, column mapping, UTF-8 encoding, and pagination limits."
    },
    {
      "title": "Add request idempotency to the plan upgrade flow to prevent duplicate charges",
      "reason": "Duplicate billing accounts for 15% of tickets (3/20), all escalated, and customers report being charged twice from a single upgrade click. This indicates the payment endpoint lacks idempotency—likely a race condition or double-submit from the frontend with no deduplication key. Adding an idempotency token to the upgrade request and server-side deduplication check would prevent the double charge, eliminate the refund-handling escalations, and restore trust in the billing system."
    }
  ]
}
